// Orchestrator-based Saga
@Service
public class OrderSagaOrchestrator {
    @Autowired private OrderRepository orderRepo;
    @Autowired private PaymentClient paymentClient;
    @Autowired private InventoryClient inventoryClient;
    @Autowired private KafkaTemplate<String, SagaEvent>
        kafkaTemplate;

    @Transactional
    public void executeOrderSaga(Order order) {
        // Step 1: Create order
        order.setStatus("PENDING");
        orderRepo.save(order);

        try {
            // Step 2: Request payment
            PaymentResult payment =
                paymentClient.pay(order.getId(),
                order.getAmount());
            if (!payment.isSuccess()) {
                compensateOrder(order);
                return;
            }

            // Step 3: Reserve inventory
            InventoryResult inventory =
                inventoryClient.reserve(
                order.getItems());
            if (!inventory.isSuccess()) {
                compensatePayment(payment);
                compensateOrder(order);
                return;
            }

            // Step 4: Confirm order
            order.setStatus("CONFIRMED");
            orderRepo.save(order);
            kafkaTemplate.send("saga-events",
                new OrderConfirmedEvent(order.getId()));
        } catch (Exception ex) {
            compensateOrder(order);
        }
    }

    private void compensatePayment(PaymentResult p) {
        paymentClient.refund(p.getPaymentId());
    }

    private void compensateOrder(Order order) {
        order.setStatus("FAILED");
        orderRepo.save(order);
    }
}

