// Detect Full GCs
public class GCDetector {
    static long lastFullGCCount = 0;
    public static void detectFullGC() {
        for (GarbageCollectorMXBean bean : ManagementFactory.getGarbageCollectorMXBeans()) {
            if (bean.getName().contains("Full")) {
                long current = bean.getCollectionCount();
                if (current > lastFullGCCount) {
                    System.out.println("FULL GC DETECTED");
                    lastFullGCCount = current;
                }
            }
        }
    }
}

