public class STWMeasurement {
    public static void main(String[] args) throws Exception {
        while (true) {
            long before = System.nanoTime();
            byte[] arr = new byte[100 * 1024 * 1024];
            long after = System.nanoTime();
            long pause = (after - before) / 1_000_000;
